import { useEffect, useMemo, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { deleteVehicle, getVehicles } from "../../api/vehicleApi";
import { getAuth } from "../../utils/auth";

export default function VehicleList() {
  const [vehicles, setVehicles] = useState([]);
  const [typeFilter, setTypeFilter] = useState("all");
  const [loading, setLoading] = useState(false);
  const [imageIndices, setImageIndices] = useState({}); // Track current image index for each vehicle

  const navigate = useNavigate();

  const auth = getAuth();
  const role = auth?.role;
  const canManageVehicles = role === "admin" || role === "manager";

  const load = async () => {
    setLoading(true);
    try {
      const res = await getVehicles();
      setVehicles(res.data || []);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load vehicles");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const vehicleTypes = useMemo(() => {
    const s = new Set(vehicles.map((v) => v.type).filter(Boolean));
    return ["all", ...Array.from(s)];
  }, [vehicles]);

  const filtered = useMemo(() => {
    if (typeFilter === "all") return vehicles;
    return vehicles.filter((v) => v.type === typeFilter);
  }, [vehicles, typeFilter]);

  const stats = useMemo(() => {
    const total = vehicles.length;
    const available = vehicles.filter((v) => v.status === "available").length;
    const reserved = vehicles.filter((v) => v.status === "reserved").length;
    const sold = vehicles.filter((v) => v.status === "sold").length;
    const totalValue = vehicles.reduce((sum, v) => sum + Number(v.price || 0), 0);

    return { total, available, reserved, sold, totalValue };
  }, [vehicles]);

  const bookNow = (vehicleId, status) => {
    if (status !== "available") return alert("This vehicle is not available for booking.");
    if (!localStorage.getItem("token")) {
      alert("Please login to book an appointment.");
      return navigate("/login");
    }
    navigate("/book-appointment", { state: { vehicleId } });
  };

  const onDelete = async (id) => {
    if (!canManageVehicles) return alert("Access denied");
    if (!window.confirm("Delete this vehicle permanently?")) return;

    try {
      await deleteVehicle(id);
      setVehicles((prev) => prev.filter((v) => v._id !== id));
      alert("Vehicle deleted");
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  const badgeClass = (status) => {
    if (status === "available") return "badge badgeOk";
    if (status === "reserved") return "badge badgeWarn";
    if (status === "sold") return "badge badgeBad";
    return "badge";
  };

  const getCover = (v) => {
    const imageUrl = v?.images?.[0]?.url;
    if (!imageUrl) return "";
    // Convert relative URL to full backend URL
    return imageUrl.startsWith("http") ? imageUrl : `http://localhost:8070${imageUrl}`;
  };

  return (
    <div className="page">
      {/* Page Header */}
      <div className="pageHead">
        <div>
          <div className="pageTitle">Vehicle Inventory</div>
          <div className="pageSub">Manage and browse all available vehicles</div>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="kpiGrid">
        <div className="kpiCard">
          <div className="kpiLabel">Total Vehicles</div>
          <div className="kpiValue">{loading ? "—" : stats.total}</div>
          <div className="kpiSub">All inventory items</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Available</div>
          <div className="kpiValue">{loading ? "—" : stats.available}</div>
          <div className="kpiSub">Ready for booking</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Reserved</div>
          <div className="kpiValue">{loading ? "—" : stats.reserved}</div>
          <div className="kpiSub">Pending transactions</div>
        </div>

        <div className="kpiCard">
          <div className="kpiLabel">Total Value</div>
          <div className="kpiValue">
            {loading ? "—" : `LKR ${Math.round(stats.totalValue / 1000)}K`}
          </div>
          <div className="kpiSub">Combined inventory value</div>
        </div>
      </div>

      {/* Filter & Actions Card */}
      <div className="card cardPad" style={{ marginBottom: 14 }}>
        <div className="row" style={{ alignItems: "center", flexWrap: "wrap" }}>
          <div>
            <div className="sectionTitle">Vehicle Management</div>
            <div className="sub">Filter and manage your vehicle inventory</div>
          </div>

          <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
            <select
              className="select"
              style={{ minWidth: 180 }}
              value={typeFilter}
              onChange={(e) => setTypeFilter(e.target.value)}
            >
              {vehicleTypes.map((t) => (
                <option key={t} value={t}>
                  {t === "all" ? "All Types" : t}
                </option>
              ))}
            </select>

            <button className="btn" onClick={load} disabled={loading}>
              {loading ? "Loading..." : "Refresh"}
            </button>

            {canManageVehicles && (
              <Link className="btn btnPrimary" to="/vehicles/add">
                + Add Vehicle
              </Link>
            )}
          </div>
        </div>
      </div>

      {/* Vehicle Grid */}
      {loading ? (
        <div className="card cardPad" style={{ textAlign: "center", padding: "40px 20px" }}>
          <div className="muted">Loading vehicles...</div>
        </div>
      ) : filtered.length === 0 ? (
        <div className="card cardPad" style={{ textAlign: "center", padding: "40px 20px" }}>
          <div className="muted">No vehicles found for the selected type.</div>
        </div>
      ) : (
        <div className="grid4">
          {filtered.map((v) => {
            const cover = getCover(v);

            return (
              <div key={v._id} className="card vehicleCard" style={{ overflow: "hidden", display: "flex", flexDirection: "column" }}>
                {/* Vehicle Image Carousel */}
                <ImageCarousel vehicle={v} isCompact={true} onIndexChange={(newIndex) => {
                  setImageIndices((prev) => ({ ...prev, [v._id]: newIndex }));
                }} />

                {/* Vehicle Info */}
                <div style={{ flex: 1, display: "flex", flexDirection: "column", padding: "12px" }}>
                  <div style={{ marginBottom: "8px" }}>
                    <div style={{ fontWeight: 700, fontSize: "14px", color: "var(--text)", lineHeight: "1.3" }}>
                      {v.brand}
                    </div>
                    <div style={{ fontSize: "12px", color: "var(--text-muted)", marginTop: "2px", lineHeight: "1.3" }}>
                      {v.type} • {v.year}
                    </div>
                  </div>

                  <div style={{ marginBottom: "8px" }}>
                    <div style={{ fontSize: "13px", fontWeight: 600, color: "var(--text)" }}>
                      LKR {Number(v.price || 0).toLocaleString()}
                    </div>
                  </div>

                  <div style={{ flex: 1 }} />

                  <div style={{ display: "flex", gap: "6px", marginBottom: "8px" }}>
                    <span className={badgeClass(v.status)}>{v.status}</span>
                  </div>

                  <div style={{ display: "flex", gap: "6px", flexWrap: "wrap" }}>
                    <button
                      className="btn btnSmall btnPrimary"
                      onClick={() => bookNow(v._id, v.status)}
                      disabled={v.status !== "available"}
                      style={{ flex: 1, opacity: v.status !== "available" ? 0.5 : 1, fontSize: "12px" }}
                    >
                      Book
                    </button>

                    {canManageVehicles && (
                      <>
                        <button 
                          className="btn btnSmall" 
                          onClick={() => navigate(`/vehicles/edit/${v._id}`)}
                          style={{ padding: "6px 10px", fontSize: "12px" }}
                        >
                          Edit
                        </button>
                        <button 
                          className="btn btnSmall" 
                          onClick={() => onDelete(v._id)}
                          style={{ padding: "6px 10px", fontSize: "12px" }}
                        >
                          ✕
                        </button>
                      </>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// Image Carousel Component
function ImageCarousel({ vehicle, onIndexChange }) {
  const [currentIndex, setCurrentIndex] = useState(0);

  // Get formatted image URLs
  const images = useMemo(() => {
    return (vehicle?.images || []).map((img) => ({
      url: img.url.startsWith("http") ? img.url : `http://localhost:8070${img.url}`,
      filename: img.filename,
    }));
  }, [vehicle]);

  const currentImage = images.length > 0 ? images[currentIndex] : null;

  // Auto-play carousel
  useEffect(() => {
    if (images.length <= 1) return;

    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % images.length);
    }, 4000); // Change image every 4 seconds

    return () => clearInterval(interval);
  }, [images.length]);

  const goToPrevious = () => {
    const newIndex = currentIndex === 0 ? images.length - 1 : currentIndex - 1;
    setCurrentIndex(newIndex);
    onIndexChange(newIndex);
  };

  const goToNext = () => {
    const newIndex = (currentIndex + 1) % images.length;
    setCurrentIndex(newIndex);
    onIndexChange(newIndex);
  };

  if (images.length === 0) {
    return (
      <div style={{ width: "100%", aspectRatio: "4 / 3", background: "#f3f4f6", display: "grid", placeItems: "center", color: "#6b7280", fontSize: "13px", fontWeight: "600" }}>
        No Photos
      </div>
    );
  }

  return (
    <div style={{ position: "relative", width: "100%", aspectRatio: "4 / 3", background: "#f3f4f6", overflow: "hidden", display: "flex", alignItems: "center", justifyContent: "center" }}>
      {/* Main Image */}
      {currentImage && (
        <img
          src={currentImage.url}
          alt={`${vehicle.brand} ${currentIndex + 1}`}
          style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
        />
      )}

      {/* Previous Button */}
      {images.length > 1 && (
        <button
          onClick={goToPrevious}
          style={{
            position: "absolute",
            left: 8,
            top: "50%",
            transform: "translateY(-50%)",
            background: "rgba(0, 0, 0, 0.5)",
            color: "white",
            border: "none",
            width: 36,
            height: 36,
            borderRadius: 4,
            cursor: "pointer",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: 18,
            fontWeight: "bold",
            transition: "background 0.2s",
            zIndex: 10,
          }}
          onMouseEnter={(e) => e.target.style.background = "rgba(0, 0, 0, 0.8)"}
          onMouseLeave={(e) => e.target.style.background = "rgba(0, 0, 0, 0.5)"}
        >
          ‹
        </button>
      )}

      {/* Next Button */}
      {images.length > 1 && (
        <button
          onClick={goToNext}
          style={{
            position: "absolute",
            right: 8,
            top: "50%",
            transform: "translateY(-50%)",
            background: "rgba(0, 0, 0, 0.5)",
            color: "white",
            border: "none",
            width: 36,
            height: 36,
            borderRadius: 4,
            cursor: "pointer",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: 18,
            fontWeight: "bold",
            transition: "background 0.2s",
            zIndex: 10,
          }}
          onMouseEnter={(e) => e.target.style.background = "rgba(0, 0, 0, 0.8)"}
          onMouseLeave={(e) => e.target.style.background = "rgba(0, 0, 0, 0.5)"}
        >
          ›
        </button>
      )}

      {/* Image Counter */}
      {images.length > 1 && (
        <div
          style={{
            position: "absolute",
            bottom: 8,
            right: 8,
            background: "rgba(0, 0, 0, 0.6)",
            color: "white",
            padding: "4px 8px",
            borderRadius: 4,
            fontSize: "12px",
            fontWeight: "600",
            zIndex: 10,
          }}
        >
          {currentIndex + 1} / {images.length}
        </div>
      )}

      {/* Image Indicators (Dots) */}
      {images.length > 1 && (
        <div
          style={{
            position: "absolute",
            bottom: 8,
            left: "50%",
            transform: "translateX(-50%)",
            display: "flex",
            gap: 6,
            zIndex: 10,
          }}
        >
          {images.map((_, idx) => (
            <button
              key={idx}
              onClick={() => {
                setCurrentIndex(idx);
                onIndexChange(idx);
              }}
              style={{
                width: 8,
                height: 8,
                borderRadius: "50%",
                background: idx === currentIndex ? "white" : "rgba(255, 255, 255, 0.5)",
                border: "none",
                cursor: "pointer",
                transition: "background 0.2s",
              }}
              title={`Go to image ${idx + 1}`}
            />
          ))}
        </div>
      )}
    </div>
  );
}

function InfoRow({ label, value, clamp }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", gap: 14 }}>
      <div style={{ opacity: 0.65, fontWeight: 800, fontSize: "13px" }}>{label}</div>
      <div
        style={{
          fontWeight: 900,
          textAlign: "right",
          maxWidth: 220,
          overflow: "hidden",
          textOverflow: "ellipsis",
          whiteSpace: clamp ? "nowrap" : "normal",
          color: "var(--navy)",
          fontSize: "13px",
        }}
        title={typeof value === "string" ? value : ""}
      >
        {value}
      </div>
    </div>
  );
}
